#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct Graph {
    int V;
    int **adj;
} Graph;

// Function to create a graph
Graph* createGraph(int V) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->V = V;
    graph->adj = (int**) malloc(V * sizeof(int*));
    for (int i = 0; i < V; i++) {
        graph->adj[i] = (int*) malloc(V * sizeof(int));
        for (int j = 0; j < V; j++) {
            graph->adj[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    graph->adj[u][v] = 1;
}

// Function to detect cycle in the graph using DFS
int isCyclic(Graph* graph, int v, int* visited, int* recursionStack) {
    if (recursionStack[v]) {
        return 1;
    }
    if (visited[v]) {
        return 0;
    }
    visited[v] = 1;
    recursionStack[v] = 1;
    for (int i = 0; i < graph->V; i++) {
        if (graph->adj[v][i]) {
            if (isCyclic(graph, i, visited, recursionStack)) {
                return 1;
            }
        }
    }
    recursionStack[v] = 0;
    return 0;
}

// Function to detect cycle in the graph
int hasCycle(Graph* graph) {
    int* visited = (int*) malloc(graph->V * sizeof(int));
    int* recursionStack = (int*) malloc(graph->V * sizeof(int));
    for (int i = 0; i < graph->V; i++) {
        visited[i] = 0;
        recursionStack[i] = 0;
    }
    for (int i = 0; i < graph->V; i++) {
        if (!visited[i]) {
            if (isCyclic(graph, i, visited, recursionStack)) {
                return 1;
            }
        }
    }
    return 0;
}

int main() {
    int V, E;
    scanf("%d %d", &V, &E);
    Graph* graph = createGraph(V);
    for (int i = 0; i < E; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(graph, u-1, v-1);
    }
    if (hasCycle(graph)) {
        printf("Cycle detected\n");
    } else {
        printf("No cycle\n");
    }
    return 0;
}

