#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool hasCycle(int V, vector<vector<int>>& adj) {
        vector<int> visited(V, 0);
        vector<int> recursionStack(V, 0);
        for (int i = 0; i < V; i++) {
            if (!visited[i]) {
                if (isCyclic(adj, i, visited, recursionStack)) {
                    return true;
                }
            }
        }
        return false;
    }

    bool isCyclic(vector<vector<int>>& adj, int v, vector<int>& visited, vector<int>& recursionStack) {
        if (recursionStack[v]) {
            return true;
        }
        if (visited[v]) {
            return false;
        }
        visited[v] = 1;
        recursionStack[v] = 1;
        for (int i = 0; i < adj[v].size(); i++) {
            if (isCyclic(adj, adj[v][i], visited, recursionStack)) {
                return true;
            }
        }
        recursionStack[v] = 0;
        return false;
    }
};

int main() {
    int V, E;
    cin >> V >> E;
    vector<vector<int>> adj(V);
    for (int i = 0; i < E; i++) {
        int u, v;
        cin >> u >> v;
        adj[u-1].push_back(v-1);
    }
    Solution obj;
    if (obj.hasCycle(V, adj)) {
        cout << "Cycle detected" << endl;
    } else {
        cout << "No cycle" << endl;
    }
    return 0;
}

