import java.util.*;

class Solution {
    public boolean hasCycle(int V, List<List<Integer>> adj) {
        int[] visited = new int[V];
        int[] recursionStack = new int[V];
        for (int i = 0; i < V; i++) {
            if (visited[i] == 0) {
                if (isCyclic(adj, i, visited, recursionStack)) {
                    return true;
                }
            }
        }
        return false;
    }

    public boolean isCyclic(List<List<Integer>> adj, int v, int[] visited, int[] recursionStack) {
        if (recursionStack[v] == 1) {
            return true;
        }
        if (visited[v] == 1) {
            return false;
        }
        visited[v] = 1;
        recursionStack[v] = 1;
        for (int i = 0; i < adj.get(v).size(); i++) {
            if (isCyclic(adj, adj.get(v).get(i), visited, recursionStack)) {
                return true;
            }
        }
        recursionStack[v] = 0;
        return false;
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int V = scanner.nextInt();
        int E = scanner.nextInt();
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < V; i++) {
            adj.add(new ArrayList<>());
        }
        for (int i = 0; i < E; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            adj.get(u-1).add(v-1);
        }
        Solution obj = new Solution();
        if (obj.hasCycle(V, adj)) {
            System.out.println("Cycle detected");
        } else {
            System.out.println("No cycle");
        }
    }
}

